"use client";

import useSWR from "swr";
import Link from "next/link";
import { useState, useEffect } from "react";

// データを取得するための関数
const fetcher = (url: string) => fetch(url).then((res) => res.json());

interface User {
  id: string;
  studentId: string;
  name: string;
  email: string;
  currentSeat: string | null;
  logs?: { timestamp: string }[];
}

export default function AdminPage() {
  // 3秒ごとに自動でデータを再取得する設定
  const { data: users, error, mutate } = useSWR<User[]>("/api/admin/active-users", fetcher, {
    refreshInterval: 3000,
  });

  const [loadingId, setLoadingId] = useState<string | null>(null);

  const handleForceLogout = async (userId: string) => {
    if (!window.confirm("この生徒を強制退出させますか？")) return;

    setLoadingId(userId);
    try {
      const res = await fetch("/api/admin/force-logout", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ userId }),
      });

      if (!res.ok) {
        alert("退出処理に失敗しました");
      } else {
        mutate();
      }
    } catch (err) {
      alert("通信エラーが発生しました");
    } finally {
      setLoadingId(null);
    }
  };

  // 滞在時間の計算用（1分ごとに再描画させるためのステート）
  const [now, setNow] = useState<Date>(new Date());
  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 60000);
    return () => clearInterval(timer);
  }, []);

  const formatInTimeAndDuration = (logs?: { timestamp: string }[]) => {
    if (!logs || logs.length === 0) return { inTime: "-", duration: "-" };

    const inDate = new Date(logs[0].timestamp);
    const inTimeStr = inDate.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });

    const ms = now.getTime() - inDate.getTime();
    if (ms <= 0) return { inTime: inTimeStr, duration: "0分" };

    const totalMinutes = Math.floor(ms / 60000);
    const hours = Math.floor(totalMinutes / 60);
    const minutes = totalMinutes % 60;
    const durationStr = hours > 0 ? `${hours}時間${minutes}分` : `${minutes}分`;

    return { inTime: inTimeStr, duration: durationStr };
  };

  if (error) return <div className="p-8 text-red-500">エラーが発生しました</div>;
  if (!users) return <div className="p-8">読み込み中...</div>;

  return (
    <div className="min-h-screen bg-gray-50 text-black p-8">
      <div className="max-w-5xl mx-auto">
        <div className="flex justify-between items-center mb-8">
          <h1 className="text-3xl font-bold">在室者リスト (管理画面)</h1>
          <div className="flex space-x-4 items-center">
            <Link href="/admin/users" className="text-indigo-600 hover:underline font-bold">
              ユーザー管理（有効期限設定）
            </Link>
            <Link href="/admin/history" className="text-indigo-600 hover:underline font-bold">
              日別履歴表示
            </Link>
            <span className="bg-green-100 text-green-800 text-lg font-bold px-4 py-2 rounded-full">
              現在 {users.length} 名
            </span>
          </div>
        </div>

        <div className="bg-white shadow-md rounded-lg overflow-hidden">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-100">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">
                  学籍番号
                </th>
                <th className="px-6 py-3 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">
                  氏名
                </th>
                <th className="px-6 py-3 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">
                  座席
                </th>
                <th className="px-6 py-3 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">
                  入室時間
                </th>
                <th className="px-6 py-3 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">
                  経過・状態
                </th>
                <th className="px-6 py-3 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">
                  操作
                </th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {users.length === 0 ? (
                <tr>
                  <td colSpan={5} className="px-6 py-12 text-center text-gray-500">
                    現在、在室している生徒はいません。
                  </td>
                </tr>
              ) : (
                users.map((user) => (
                  <tr key={user.id} className="hover:bg-gray-50 transition">
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                      {user.studentId}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      {user.name}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      {user.currentSeat || "指定なし"}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900 font-medium">
                      {formatInTimeAndDuration(user.logs).inTime}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex flex-col space-y-1">
                        <span className="px-2 inline-flex text-xs leading-5 font-semibold rounded-full bg-green-100 text-green-800 self-start">
                          在室中
                        </span>
                        <span className="text-xs text-gray-500 font-bold">
                          {formatInTimeAndDuration(user.logs).duration}
                        </span>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                      <button
                        onClick={() => handleForceLogout(user.id)}
                        disabled={loadingId === user.id}
                        className={`px-4 py-2 rounded text-white ${
                          loadingId === user.id ? "bg-red-300" : "bg-red-500 hover:bg-red-600"
                        }`}
                      >
                        {loadingId === user.id ? "処理中..." : "強制退出"}
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>

        <div className="mt-8 text-center">
          <Link href="/" className="text-blue-500 underline hover:text-blue-700">
            トップページへ戻る
          </Link>
        </div>
      </div>
    </div>
  );
}

"use client";

import useSWR from "swr";
import Link from "next/link";
import { useState } from "react";

const fetcher = (url: string) => fetch(url).then((res) => res.json());

interface User {
  id: string;
  studentId: string | null;
  name: string | null;
  email: string | null;
  validFrom: string | null;
  validUntil: string | null;
}

export default function AdminUsersPage() {
  const { data: users, error, mutate } = useSWR<User[]>("/api/admin/users", fetcher);
  const [editingUserId, setEditingUserId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState({ validFrom: "", validUntil: "" });

  if (error) return <div className="p-8 text-red-500">エラーが発生しました</div>;
  if (!users) return <div className="p-8">読み込み中...</div>;

  const handleEditClick = (user: User) => {
    setEditingUserId(user.id);
    setEditForm({
      validFrom: user.validFrom ? new Date(user.validFrom).toISOString().split('T')[0] : "",
      validUntil: user.validUntil ? new Date(user.validUntil).toISOString().split('T')[0] : "",
    });
  };

  const handleSave = async (userId: string) => {
    try {
      const res = await fetch(`/api/admin/users/${userId}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          validFrom: editForm.validFrom || null,
          validUntil: editForm.validUntil || null,
        }),
      });

      if (res.ok) {
        mutate();
        setEditingUserId(null);
      } else {
        alert("保存に失敗しました");
      }
    } catch (error) {
      alert("通信エラーが発生しました");
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 text-black p-8">
      <div className="max-w-6xl mx-auto">
        <div className="flex justify-between items-center mb-8">
          <h1 className="text-3xl font-bold">ユーザー管理 (利用期間設定)</h1>
          <Link href="/admin" className="text-blue-500 hover:underline">
            ← 在室者リストへ戻る
          </Link>
        </div>

        <div className="bg-white shadow-md rounded-lg overflow-hidden">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-100">
              <tr>
                <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">学籍番号</th>
                <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">氏名</th>
                <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">有効期間（開始）</th>
                <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">有効期間（終了）</th>
                <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">操作</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {users.map((user) => (
                <tr key={user.id} className="hover:bg-gray-50 transition">
                  <td className="px-4 py-4 whitespace-nowrap text-sm font-medium text-gray-900">{user.studentId}</td>
                  <td className="px-4 py-4 whitespace-nowrap text-sm text-gray-900">{user.name}</td>

                  {editingUserId === user.id ? (
                    <>
                      <td className="px-4 py-4 whitespace-nowrap text-sm">
                        <input
                          type="date"
                          value={editForm.validFrom}
                          onChange={(e) => setEditForm({ ...editForm, validFrom: e.target.value })}
                          className="border rounded px-2 py-1 bg-white"
                        />
                      </td>
                      <td className="px-4 py-4 whitespace-nowrap text-sm">
                        <input
                          type="date"
                          value={editForm.validUntil}
                          onChange={(e) => setEditForm({ ...editForm, validUntil: e.target.value })}
                          className="border rounded px-2 py-1 bg-white"
                        />
                      </td>
                      <td className="px-4 py-4 whitespace-nowrap text-sm">
                        <button
                          onClick={() => handleSave(user.id)}
                          className="bg-blue-600 text-white px-3 py-1 rounded hover:bg-blue-700 mr-2"
                        >
                          保存
                        </button>
                        <button
                          onClick={() => setEditingUserId(null)}
                          className="bg-gray-300 text-gray-800 px-3 py-1 rounded hover:bg-gray-400"
                        >
                          キャンセル
                        </button>
                      </td>
                    </>
                  ) : (
                    <>
                      <td className="px-4 py-4 whitespace-nowrap text-sm text-gray-500">
                        {user.validFrom ? new Date(user.validFrom).toLocaleDateString() : "未設定"}
                      </td>
                      <td className="px-4 py-4 whitespace-nowrap text-sm text-gray-500">
                        {user.validUntil ? new Date(user.validUntil).toLocaleDateString() : "未設定"}
                      </td>
                      <td className="px-4 py-4 whitespace-nowrap text-sm">
                        <button
                          onClick={() => handleEditClick(user)}
                          className="text-indigo-600 hover:text-indigo-900"
                        >
                          編集
                        </button>
                      </td>
                    </>
                  )}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";

// 常に最新データを取得させるため、キャッシュを無効化する設定
export const dynamic = 'force-dynamic';

export async function GET() {
  try {
    // ステータスが "IN" (在室) のユーザーを全員取得
    const activeUsers = await prisma.user.findMany({
      where: {
        currentStatus: "IN",
      },
      select: {
        id: true,
        studentId: true,
        name: true,
        email: true,
        currentSeat: true,
        logs: {
          select: {
            timestamp: true
          },
          orderBy: {
            timestamp: 'desc'
          },
          take: 1
        }
      },
      orderBy: {
        studentId: 'asc', // 学籍番号順に並べる
      },
    });

    return NextResponse.json(activeUsers);
  } catch (error) {
    return NextResponse.json({ error: "Failed to fetch users" }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";

export async function GET(req: Request) {
  try {
    const { searchParams } = new URL(req.url);
    const dateParam = searchParams.get("date");

    // dateParamがなければ今日のJST日付文字列(YYYY-MM-DD)を取得
    let targetDateStr = dateParam;
    if (!targetDateStr) {
      const nowJST = new Date(new Date().toLocaleString("en-US", { timeZone: "Asia/Tokyo" }));
      targetDateStr = `${nowJST.getFullYear()}-${String(nowJST.getMonth() + 1).padStart(2, '0')}-${String(nowJST.getDate()).padStart(2, '0')}`;
    }

    // YYYY-MM-DD 文字列に JST のオフセットを付けて Date オブジェクト化する
    const startOfDay = new Date(`${targetDateStr}T00:00:00+09:00`);
    const endOfDay = new Date(`${targetDateStr}T23:59:59+09:00`);

    // 不正な日付形式かチェック
    if (isNaN(startOfDay.getTime()) || isNaN(endOfDay.getTime())) {
      return NextResponse.json({ error: "Invalid date format" }, { status: 400 });
    }

    const logs = await prisma.attendanceLog.findMany({
      where: {
        timestamp: {
          gte: startOfDay,
          lte: endOfDay
        }
      },
      include: {
        user: {
          select: { name: true, studentId: true }
        }
      },
      orderBy: { timestamp: "asc" }
    });

    // ユーザーごとに入退室のペアを作成
    // ※今回は簡易的に1日1回のIN/OUTペアのみ、または最新のペアのみを考慮するのではなく、複数回の出入りをまとめて表示するリスト形式にします
    const userGroups: Record<string, any> = {};

    logs.forEach(log => {
      const uId = log.userId;
      if (!userGroups[uId]) {
        userGroups[uId] = {
          userId: uId,
          name: log.user.name || "不明",
          studentId: log.user.studentId || "不明",
          sessions: [],
          currentSession: null
        };
      }

      if (log.action === "IN") {
        userGroups[uId].currentSession = {
          inTime: log.timestamp,
          outTime: null,
          durationMs: 0,
          remarks: log.remarks || null
        };
        userGroups[uId].sessions.push(userGroups[uId].currentSession);
      } else if (log.action === "OUT") {
        const session = userGroups[uId].currentSession;
        if (session) {
          session.outTime = log.timestamp;
          session.durationMs = new Date(log.timestamp).getTime() - new Date(session.inTime).getTime();
          session.remarks = [session.remarks, log.remarks].filter(Boolean).join(" / ");
          userGroups[uId].currentSession = null; // reset
        } else {
          // OUTから始まる異常系（前日のINのまま）は今回はスキップか前日0時からの換算にするが、
          // 簡易実装として孤立したOUTとして記録する
          userGroups[uId].sessions.push({
            inTime: null,
            outTime: log.timestamp,
            durationMs: 0,
            remarks: log.remarks || "入室記録なし"
          });
        }
      }
    });

    // フラットなリストに変換（1セッション1行）
    const resultList: any[] = [];
    Object.values(userGroups).forEach(group => {
      group.sessions.forEach((s: any) => {
        resultList.push({
          userId: group.userId,
          name: group.name,
          studentId: group.studentId,
          inTime: s.inTime,
          outTime: s.outTime,
          durationMs: s.durationMs,
          remarks: s.remarks
        });
      });
    });

    // INが早い順にソート
    resultList.sort((a, b) => {
      const aTime = a.inTime ? new Date(a.inTime).getTime() : new Date(a.outTime).getTime();
      const bTime = b.inTime ? new Date(b.inTime).getTime() : new Date(b.outTime).getTime();
      return aTime - bTime;
    });

    return NextResponse.json(resultList);
  } catch (error) {
    console.error("History fetch error:", error);
    return NextResponse.json({ error: "Failed to fetch history" }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";

export async function GET() {
  try {
    const users = await prisma.user.findMany({
      orderBy: { studentId: "asc" }
    });
    return NextResponse.json(users);
  } catch (error) {
    return NextResponse.json({ error: "Failed to fetch users" }, { status: 500 });
  }
}

import NextAuth, { NextAuthOptions } from "next-auth";
import GoogleProvider from "next-auth/providers/google";
import { PrismaAdapter } from "@auth/prisma-adapter";
import { prisma } from "@/lib/prisma";

// ▼ ここに export const authOptions を追加しました
export const authOptions: NextAuthOptions = {
  adapter: PrismaAdapter(prisma) as any,
  session: {
    // Middleware(withAuth)はJWTでないと動作しないため、PrismaAdapter使用時も強制的にJWTを使用する
    strategy: "jwt"
  },
  providers:[
    GoogleProvider({
      clientId: process.env.GOOGLE_CLIENT_ID || "",
      clientSecret: process.env.GOOGLE_CLIENT_SECRET || "",
    }),
  ],
  callbacks: {
    // ▼ ここから追加: ログイン時のドメインチェック
    async signIn({ user }) {
      const allowedDomain = process.env.ALLOWED_DOMAIN || "niigata-meikun.ed.jp";
      // メアドが存在し、かつ指定ドメインで終わる場合のみ true (許可)
      if (user.email && user.email.endsWith(`@${allowedDomain}`)) {
        return true;
      }
      // それ以外はアクセス拒否のエラーページへ弾く
      return "/api/auth/signin?error=AccessDenied";
    },
    // ▲ ここまで追加

    async session({ session, user }) {
      if (session.user) {
        session.user.id = user.id;
        session.user.studentId = user.studentId;
        session.user.isRegistered = user.isRegistered;
        session.user.currentStatus = user.currentStatus;
      }
      return session;
    },
  },
  events: {
    async createUser({ user }) {
      if (user.email) {
        const studentId = user.email.split("@")[0];
        await prisma.user.update({
          where: { id: user.id },
          data: { studentId: studentId },
        });
        console.log(`🎊 新規ユーザー登録完了: 学籍番号 ${studentId}`);
      }
    },
  },
};

const handler = NextAuth(authOptions);
export { handler as GET, handler as POST };

import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import jwt from "jsonwebtoken";
import { sendNotificationEmail } from "@/lib/mail";

export async function POST(req: Request) {
  try {
    const { token, seat } = await req.json();

    if (!token) {
      return NextResponse.json({ error: "No token provided" }, { status: 400 });
    }

    if (!process.env.NEXTAUTH_SECRET) {
      console.error("NEXTAUTH_SECRET is not set in environment variables.");
      return NextResponse.json({ error: "Server configuration error" }, { status: 500 });
    }

    // トークン検証
    const decoded: any = jwt.verify(token, process.env.NEXTAUTH_SECRET);
    const userId = decoded.userId;

    // ユーザー取得
    const user = await prisma.user.findUnique({
      where: { id: userId },
    });

    if (!user) {
      return NextResponse.json({ error: "User not found" }, { status: 404 });
    }

    const now = new Date();

    // 2. 保護者による利用許可機能（有効期限管理）
    if (user.validFrom && now < user.validFrom) {
      return NextResponse.json({ error: "利用開始日前です" }, { status: 403 });
    }
    if (user.validUntil && now > user.validUntil) {
      return NextResponse.json({ error: "利用有効期限が切れています" }, { status: 403 });
    }

    // 1. 二重読み込み防止ロジック
    const latestLog = await prisma.attendanceLog.findFirst({
      where: { userId: userId },
      orderBy: { timestamp: 'desc' },
    });

    if (latestLog) {
      const timeDiff = now.getTime() - new Date(latestLog.timestamp).getTime();
      if (timeDiff < 60 * 1000) { // 1分 (60000ms) 以内
        return NextResponse.json({ error: "連続しての打刻はできません（1分間は再アクセス不可です）" }, { status: 429 });
      }
    }

    // ステータス反転と座席の処理
    const newStatus = user.currentStatus === "IN" ? "OUT" : "IN";

    // 5. 座席管理
    let nextSeat = null;
    if (newStatus === "IN") {
      if (!seat) {
        return NextResponse.json({ error: "入室時は座席を指定してください" }, { status: 400 });
      }
      nextSeat = seat;
    }

    // DB更新
    const result = await prisma.$transaction([
      prisma.user.update({
        where: { id: userId },
        data: { 
          currentStatus: newStatus,
          currentSeat: nextSeat 
        },
      }),
      prisma.attendanceLog.create({
        data: {
          userId: userId,
          action: newStatus,
        },
      }),
    ]);

    // メール送信（非同期）
    if (user.parentEmail) {
      sendNotificationEmail(
        user.parentEmail,
        user.name || "生徒",
        newStatus as "IN" | "OUT",
        new Date()
      ).catch(err => console.error("Email error inside API:", err));
    }

    return NextResponse.json({
      success: true,
      user: result[0],
      action: newStatus,
    });

  } catch (error) {
    console.error("Checkin error:", error);
    return NextResponse.json({ error: "Invalid or expired token" }, { status: 401 });
  }
}

import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";

export async function GET() {
  try {
    const usersIn = await prisma.user.findMany({
      where: { 
        currentStatus: "IN", 
        currentSeat: { not: null } 
      },
      select: { currentSeat: true }
    });

    // 現在使用中の座席番号を配列で返す
    const occupiedSeats = usersIn.map(u => u.currentSeat);
    return NextResponse.json({ occupiedSeats });
  } catch (error) {
    return NextResponse.json({ error: "Failed to fetch seats" }, { status: 500 });
  }
}

