"use client"; // フック(useStateなど)を使うのでクライアントコンポーネントにします

import { useSession, signOut } from "next-auth/react";
import { useRouter } from "next/navigation";
import { useEffect, useState } from "react";
import { QRCodeSVG } from "qrcode.react";

export default function Home() {
  const { data: session, status } = useSession();
  const router = useRouter();
  const [qrToken, setQrToken] = useState<string>("");

  // ログインしていない場合や未登録の場合のチェック
  useEffect(() => {
    if (status === "unauthenticated") {
      router.push("/api/auth/signin");
    } else if (status === "authenticated" && session?.user?.isRegistered === false) {
      router.push("/register");
    }
  }, [status, session, router]);

  // 30秒ごとに新しいQRコード用トークンを取得する関数
  const fetchQrToken = async () => {
    try {
      const res = await fetch("/api/qr");
      const data = await res.json();
      if (data.token) {
        setQrToken(data.token);
      }
    } catch (error) {
      console.error("QRトークン取得エラー:", error);
    }
  };

  // 初回表示時と、その後30秒ごとに実行
  useEffect(() => {
    if (status === "authenticated") {
      fetchQrToken();
      const interval = setInterval(fetchQrToken, 30000); // 30秒ごと
      return () => clearInterval(interval);
    }
  }, [status]);

  if (status === "loading") {
    return <div className="flex justify-center items-center min-h-screen">読み込み中...</div>;
  }

  if (!session) return null;

  return (
    <div className="flex flex-col items-center justify-center min-h-screen bg-white text-black">
      <h1 className="text-2xl font-bold mb-4">
        こんにちは、{session.user.name || session.user.studentId}さん
      </h1>

      <div className="bg-gray-100 p-4 rounded-lg mb-8 text-center">
        <p className="text-sm text-gray-600 mb-1">現在のステータス</p>
        <p className={`text-2xl font-bold ${session.user.currentStatus === "IN" ? "text-green-600" : "text-gray-500"}`}>
          {session.user.currentStatus === "IN" ? "在室 (IN)" : "退室 (OUT)"}
        </p>
      </div>

      {/* QRコード表示エリア */}
      <div className="bg-white p-6 rounded-xl shadow-lg border border-gray-200 mb-8 flex flex-col items-center">
        {qrToken ? (
          <QRCodeSVG value={qrToken} size={200} level={"H"} />
        ) : (
          <div className="w-[200px] h-[200px] bg-gray-200 animate-pulse rounded"></div>
        )}
        <p className="text-xs text-gray-500 mt-4">QRコードは自動で更新されます</p>
      </div>

      <button 
        onClick={() => signOut()} 
        className="text-red-500 underline hover:text-red-700 text-sm"
      >
        ログアウト
      </button>
    </div>
  );
}

"use client";

import { useEffect, useRef, useState } from "react";
import { useRouter } from "next/navigation";
import useSWR from "swr";

const fetcher = (url: string) => fetch(url).then((res) => res.json());

export default function ScannerPage() {
  const [lastScanned, setLastScanned] = useState<string>("");
  const [statusMessage, setStatusMessage] = useState<string>("座席を選択してスキャン待機中...");
  const [selectedSeat, setSelectedSeat] = useState<string>("");
  const inputRef = useRef<HTMLInputElement>(null);

  // 定期的に使用中の座席を取得（5秒間隔）
  const { data: seatData, mutate: mutateSeats } = useSWR<{ occupiedSeats: string[] }>("/api/seats", fetcher, {
    refreshInterval: 5000,
  });

  // 全座席リスト (例として 1〜30番 まで)
  const allSeats = Array.from({ length: 30 }, (_, i) => `${i + 1}番`);

  // 画面を開いたときに自動で入力ボックスにフォーカスを当てる
  useEffect(() => {
    if (inputRef.current) {
      inputRef.current.focus();
    }

    // 画面をクリックしたら再フォーカス（フォーカス外れ防止）
    const handleClick = () => {
      // セレクトボックス以外をクリックしたときのみ再フォーカス
      if (document.activeElement?.tagName !== "SELECT" && inputRef.current) {
        inputRef.current.focus();
      }
    };
    window.addEventListener("click", handleClick);
    return () => window.removeEventListener("click", handleClick);
  }, []);

  // QRコードが読み込まれた（Enterキーが押された）ときの処理
  const handleScan = async (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === "Enter") {
      const token = e.currentTarget.value;
      if (!token) return;

      // 入力ボックスをクリアして次の読み取りに備える
      if (inputRef.current) {
        inputRef.current.value = "";
      }

      setStatusMessage("処理中...");

      try {
        const res = await fetch("/api/checkin", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ token, seat: selectedSeat }),
        });

        const data = await res.json();

        if (res.ok) {
          setLastScanned(`${data.user.name}さんが ${data.action === "IN" ? "入室" : "退室"} しました`);
          setStatusMessage("成功！次のQRをどうぞ");

          if (data.action === "IN") {
            // 入室後は座席選択をクリアし、座席情報を再取得
            setSelectedSeat("");
            mutateSeats();
          } else {
            // 退室の場合も座席が空くため再取得
            mutateSeats();
          }
        } else {
           setStatusMessage("エラー: " + (data.error || "読み取り失敗"));
        }
      } catch (error) {
        setStatusMessage("通信エラーが発生しました");
      }

      // スキャン後、再度入力ボックスにフォーカスを戻す
      setTimeout(() => inputRef.current?.focus(), 100);
    }
  };

  return (
    <div className="min-h-screen bg-gray-900 text-white flex flex-col items-center justify-center p-4">
      <h1 className="text-4xl font-bold mb-8">QRコード読み取り機</h1>

      <div className="mb-8 p-6 bg-gray-800 rounded-xl shadow-lg w-full max-w-2xl text-center">
        <label className="block text-xl text-gray-300 mb-4 font-bold">
          入室する座席を選んでからスキャンしてください<br />
          <span className="text-sm text-gray-500 font-normal">※退室時は座席選択不要です</span>
        </label>
        <select
          value={selectedSeat}
          onChange={(e) => setSelectedSeat(e.target.value)}
          className="w-full max-w-sm p-3 rounded-lg text-black text-xl text-center"
          onBlur={() => inputRef.current?.focus()} // 選択後フォーカスを戻す
        >
          <option value="">-- 座席未選択 --</option>
          {allSeats.map(seat => {
            const isOccupied = seatData?.occupiedSeats?.includes(seat);
            return (
              <option key={seat} value={seat} disabled={isOccupied}>
                {seat} {isOccupied ? "(使用中)" : ""}
              </option>
            );
          })}
        </select>
      </div>

      {/* 隠し入力ボックス（ここにQRリーダーが文字を入力します） */}
      <input
        ref={inputRef}
        type="text"
        className="opacity-0 absolute h-0 w-0 -z-10" // 完全に隠す（focusできるようにする）
        onKeyDown={handleScan}
        autoFocus
      />

      <div className="bg-gray-800 p-8 rounded-xl shadow-lg w-full max-w-2xl text-center">
        <p className="text-xl text-gray-400 mb-4">ステータス</p>
        <div className={`text-3xl font-bold mb-8 ${statusMessage.includes("エラー") ? "text-red-500" : "text-green-400"}`}>
          {statusMessage}
        </div>

        <div className="border-t border-gray-700 pt-8">
          <p className="text-sm text-gray-500 mb-2">直前の読み取り結果</p>
          <p className="text-2xl font-bold">{lastScanned || "まだありません"}</p>
        </div>
      </div>

      <p className="mt-8 text-gray-500 text-sm">
        ※ 画面またはセレクトボックスをクリックしてフォーカスを維持してください
      </p>
    </div>
  );
}

import { withAuth } from "next-auth/middleware";
import { NextResponse } from "next/server";

export default withAuth(
  function middleware(req) {
    // 認証済みのユーザー情報（token）はコールバック内で検証されるため
    // ここは基本的に通過させるだけでOKです
    return NextResponse.next();
  },
  {
    callbacks: {
      authorized: ({ token, req }) => {
        const path = req.nextUrl.pathname;

        // 管理者権限が必要なURLリスト
        const isAdminRoute = 
          path.startsWith("/admin") || 
          path.startsWith("/scanner") || 
          path.startsWith("/api/admin") ||
          path.startsWith("/api/checkin") ||
          path.startsWith("/api/seats");

        // アクセス先が管理者用URLの場合
        if (isAdminRoute) {
          // .env に設定した管理者リストを取得
          const adminEmails = process.env.ADMIN_EMAILS?.split(",") || [];

          // ログインしており、かつメールアドレスが管理者リストに含まれているか判定
          if (token?.email && adminEmails.includes(token.email)) {
            return true; // アクセス許可
          }
          return false; // アクセス拒否 (ログイン画面に強制リダイレクト)
        }

        // 管理者用以外の一般ルート（生徒のダッシュボード等）は、
        // ページごとのチェックに任せるため一旦通過させる
        return true; 
      },
    },
  }
);

// Middlewareを監視・発動させるURLのパターンを指定
export const config = {
  matcher: [
    "/admin/:path*", 
    "/scanner/:path*", 
    "/api/admin/:path*", 
    "/api/checkin/:path*",
    "/api/seats/:path*"
  ],
};

import NextAuth, { DefaultSession } from "next-auth"

declare module "next-auth" {
  interface Session {
    user: {
      id: string
      studentId?: string | null
      isRegistered?: boolean
      currentStatus?: string
    } & DefaultSession["user"]
  }

  interface User {
    studentId?: string | null
    isRegistered?: boolean
    currentStatus?: string
  }
}
